import { GoogleGenAI, Type } from "@google/genai";
import { SearchParams, TripSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getTravelSuggestions(params: SearchParams): Promise<TripSuggestion> {
  const prompt = `Act as a luxury travel concierge. Create a unique trip summary for:
    Location: ${params.location}
    Travelers: ${params.guests}
    Duration: From ${params.startDate} to ${params.endDate}.
    Provide insights in a luxurious, inviting tone.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            highlights: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            vibe: { type: Type.STRING },
            bestTime: { type: Type.STRING }
          },
          required: ["title", "highlights", "vibe", "bestTime"]
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      title: "Exploring " + params.location,
      highlights: ["Local Cuisine", "Historic Landmarks", "Cultural Immersion"],
      vibe: "Elegant and adventurous",
      bestTime: "Late spring or early autumn"
    };
  }
}

export async function getQuickSearchVibe(query: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Describe the 'vibe' of traveling to ${query} in exactly one short, evocative sentence.`,
  });
  return response.text || "A mysterious and enchanting journey awaits.";
}

