import React, { useState, useEffect } from 'react';
import { Icons } from '../constants';
import { SearchParams } from '../types';
import { getQuickSearchVibe } from '../services/geminiService';

interface SearchFormProps {
  onSearch: (params: SearchParams) => void;
}

const SearchForm: React.FC<SearchFormProps> = ({ onSearch }) => {
  const [params, setParams] = useState<SearchParams>({
    location: '',
    startDate: '',
    endDate: '',
    guests: 2
  });
  const [vibe, setVibe] = useState<string>('');
  const [isTyping, setIsTyping] = useState(false);

  useEffect(() => {
    if (!params.location) {
      setVibe('');
      return;
    }
    const timer = setTimeout(async () => {
      setIsTyping(false);
      const res = await getQuickSearchVibe(params.location);
      setVibe(res);
    }, 1000);
    setIsTyping(true);
    return () => clearTimeout(timer);
  }, [params.location]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch(params);
  };

  return (
    <div className="w-full max-w-5xl mx-auto px-4 -mt-12 sm:-mt-16 lg:-mt-20 relative z-10">
      <form 
        onSubmit={handleSubmit}
        className="bg-white rounded-[2.5rem] shadow-2xl p-4 md:p-8 flex flex-col lg:flex-row items-center gap-6 border border-slate-100"
      >
        <div className="flex-1 w-full flex flex-col space-y-2">
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Search />
            <span>Destination</span>
          </label>
          <input 
            type="text"
            className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
            placeholder="Where to?"
            value={params.location}
            onChange={(e) => setParams({...params, location: e.target.value})}
          />
          <div className="h-4 overflow-hidden">
             {vibe && !isTyping && (
               <p className="text-[10px] text-blue-500 font-medium italic animate-in slide-in-from-top-2 duration-300">
                 {vibe}
               </p>
             )}
          </div>
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        <div className="w-full lg:w-auto flex-1 grid grid-cols-2 gap-4">
          <div className="flex flex-col space-y-2">
            <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
              <Icons.Calendar />
              <span>Dates</span>
            </label>
            <input 
              type="date"
              className="w-full px-0 py-2 text-sm font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent"
              value={params.startDate}
              onChange={(e) => setParams({...params, startDate: e.target.value})}
            />
          </div>
          <div className="flex flex-col space-y-2">
            <label className="opacity-0">.</label>
            <input 
              type="date"
              className="w-full px-0 py-2 text-sm font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent"
              value={params.endDate}
              onChange={(e) => setParams({...params, endDate: e.target.value})}
            />
          </div>
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        <div className="w-full lg:w-48 flex flex-col space-y-2">
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Users />
            <span>Travelers</span>
          </label>
          <select 
            className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent"
            value={params.guests}
            onChange={(e) => setParams({...params, guests: parseInt(e.target.value)})}
          >
            {[1,2,3,4,5,6].map(n => (
              <option key={n} value={n}>{n} {n === 1 ? 'Guest' : 'Guests'}</option>
            ))}
