import React, { useState, useEffect, useRef } from 'react';
import { Icons, INDIAN_CITIES } from '../constants';
import { SearchParams } from '../types';
import { getQuickSearchVibe } from '../services/geminiService';

interface SearchFormProps {
  onSearch: (params: SearchParams) => void;
}

const SearchForm: React.FC<SearchFormProps> = ({ onSearch }) => {
  const [params, setParams] = useState<SearchParams>({
    location: '',
    startDate: '',
    endDate: '',
    adults: 2,
    children: 0,
    infants: 0
  });
  const [vibe, setVibe] = useState<string>('');
  const [isTyping, setIsTyping] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [showCalendar, setShowCalendar] = useState(false);
  const [showGuests, setShowGuests] = useState(false);
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const suggestionRef = useRef<HTMLDivElement>(null);
  const calendarRef = useRef<HTMLDivElement>(null);
  const guestsRef = useRef<HTMLDivElement>(null);

  // Get start of today in system timezone for comparison
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      if (suggestionRef.current && !suggestionRef.current.contains(target)) {
        setShowSuggestions(false);
      }
      if (calendarRef.current && !calendarRef.current.contains(target)) {
        setShowCalendar(false);
      }
      if (guestsRef.current && !guestsRef.current.contains(target)) {
        setShowGuests(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (!params.location) {
      setVibe('');
      setSuggestions([]);
      return;
    }

    const filtered = INDIAN_CITIES.filter(city => 
      city.toLowerCase().includes(params.location.toLowerCase())
    ).slice(0, 5);
    setSuggestions(filtered);

    const timer = setTimeout(async () => {
      setIsTyping(false);
      const res = await getQuickSearchVibe(params.location);
      setVibe(res);
    }, 1000);
    setIsTyping(true);
    return () => clearTimeout(timer);
  }, [params.location]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch(params);
    setShowSuggestions(false);
    setShowCalendar(false);
    setShowGuests(false);
  };

  const selectSuggestion = (city: string) => {
    setParams({ ...params, location: city });
    setShowSuggestions(false);
  };

  // Calendar Helpers
  const daysInMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  const firstDayOfMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth(), 1).getDay();
  const monthName = (date: Date) => date.toLocaleString('default', { month: 'long', year: 'numeric' });

  const isSelected = (day: number) => {
    const dateStr = formatDate(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day));
    return dateStr === params.startDate || dateStr === params.endDate;
  };

  const isInRange = (day: number) => {
    if (!params.startDate || !params.endDate) return false;
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    const start = new Date(params.startDate);
    const end = new Date(params.endDate);
    return date > start && date < end;
  };

  const isPast = (day: number) => {
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    date.setHours(0, 0, 0, 0);
    return date < today;
  };

  const formatDate = (date: Date) => {
    return date.toISOString().split('T')[0];
  };

  const handleDateClick = (day: number) => {
    if (isPast(day)) return;

    const clickedDate = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    const dateStr = formatDate(clickedDate);

    if (!params.startDate || (params.startDate && params.endDate)) {
      setParams({ ...params, startDate: dateStr, endDate: '' });
    } else {
      const start = new Date(params.startDate);
      if (clickedDate < start) {
        setParams({ ...params, startDate: dateStr, endDate: '' });
      } else {
        setParams({ ...params, endDate: dateStr });
        setShowCalendar(false);
      }
    }
  };

  const displayDateRange = () => {
    if (!params.startDate) return "Select dates";
    const start = new Date(params.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    if (!params.endDate) return `${start} - ...`;
    const end = new Date(params.endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    return `${start} - ${end}`;
  };

  const updateGuests = (type: 'adults' | 'children' | 'infants', delta: number) => {
    const currentVal = params[type];
    const newVal = Math.max(type === 'adults' ? 1 : 0, currentVal + delta);
    setParams({ ...params, [type]: newVal });
  };

  const displayGuestSummary = () => {
    const total = params.adults + params.children + params.infants;
    if (total === 0) return "Add guests";
    let summary = `${params.adults} Adults`;
    if (params.children > 0) summary += `, ${params.children} Child${params.children > 1 ? 'ren' : ''}`;
    if (params.infants > 0) summary += `, ${params.infants} Infant${params.infants > 1 ? 's' : ''}`;
    return summary;
  };

  return (
    <div className="w-full max-w-5xl mx-auto px-4 -mt-12 sm:-mt-16 lg:-mt-20 relative z-10">
      <form 
        onSubmit={handleSubmit}
        className="bg-white rounded-[2.5rem] shadow-2xl p-4 md:p-8 flex flex-col lg:flex-row items-center gap-6 border border-slate-100 relative"
      >
        {/* Destination Section */}
        <div className="flex-[1.5] w-full flex flex-col space-y-2 relative" ref={suggestionRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Search />
            <span>Destination</span>
          </label>
          <input 
            type="text"
            className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
            placeholder="Where to?"
            autoComplete="off"
            value={params.location}
            onFocus={() => setShowSuggestions(true)}
            onChange={(e) => {
              setParams({...params, location: e.target.value});
              setShowSuggestions(true);
            }}
          />

          {showSuggestions && suggestions.length > 0 && (
            <div className="absolute top-full left-0 w-full mt-4 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 z-50 animate-in fade-in slide-in-from-top-2 duration-200">
              {suggestions.map((city, idx) => (
                <button
                  key={idx}
                  type="button"
                  onClick={() => selectSuggestion(city)}
                  className="w-full px-6 py-3 text-left hover:bg-orange-50 flex items-center space-x-3 group transition-colors"
                >
                  <div className="p-2 bg-slate-50 rounded-lg text-slate-400 group-hover:bg-orange-100 group-hover:text-orange-600 transition-colors">
                    <Icons.MapPin />
                  </div>
                  <span className="text-slate-700 font-medium">{city}</span>
                </button>
              ))}
            </div>
          )}

          <div className="h-4 overflow-hidden">
             {vibe && !isTyping && !showSuggestions && (
               <p className="text-[10px] text-orange-600 font-medium italic animate-in slide-in-from-top-2 duration-300">
                 {vibe}
               </p>
             )}
          </div>
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        {/* Date Picker Section */}
        <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={calendarRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Calendar />
            <span>Travel Window</span>
          </label>
          <button 
            type="button"
            onClick={() => { setShowCalendar(!showCalendar); setShowGuests(false); }}
            className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 bg-transparent outline-none truncate"
          >
            {displayDateRange()}
          </button>

          {showCalendar && (
            <div className="absolute top-full left-0 lg:-left-20 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-6 z-50 animate-in fade-in slide-in-from-top-2 duration-200">
              <div className="flex justify-between items-center mb-6">
                <button 
                  type="button" 
                  onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))}
                  className="p-2 hover:bg-slate-50 rounded-full transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg>
                </button>
                <span className="font-serif font-bold text-slate-800">{monthName(currentMonth)}</span>
                <button 
                  type="button" 
                  onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))}
                  className="p-2 hover:bg-slate-50 rounded-full transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                </button>
              </div>

              <div className="grid grid-cols-7 gap-1 text-center mb-2">
                {['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'].map(d => (
                  <span key={d} className="text-[10px] font-bold text-slate-300 uppercase">{d}</span>
                ))}
              </div>

              <div className="grid grid-cols-7 gap-1">
                {Array.from({ length: firstDayOfMonth(currentMonth) }).map((_, i) => <div key={`empty-${i}`} />)}
                {Array.from({ length: daysInMonth(currentMonth) }).map((_, i) => {
                  const day = i + 1;
                  const selected = isSelected(day);
                  const inRange = isInRange(day);
                  const disabled = isPast(day);

                  return (
                    <button
                      key={day}
                      type="button"
                      disabled={disabled}
                      onClick={() => handleDateClick(day)}
                      className={`
                        h-9 w-9 text-xs font-semibold rounded-full transition-all flex items-center justify-center
                        ${selected ? 'bg-orange-500 text-white shadow-lg shadow-orange-200' : ''}
                        ${inRange && !selected ? 'bg-orange-50 text-orange-600 rounded-none' : ''}
                        ${!selected && !inRange && !disabled ? 'hover:bg-orange-50 text-slate-600' : ''}
                        ${disabled ? 'text-slate-200 cursor-not-allowed' : 'cursor-pointer'}
                      `}
                    >
                      {day}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        {/* Detailed Guest Section */}
        <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={guestsRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Users />
            <span>Travelers</span>
          </label>
          <button 
            type="button"
            onClick={() => { setShowGuests(!showGuests); setShowCalendar(false); }}
            className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 bg-transparent outline-none truncate"
          >
            {displayGuestSummary()}
          </button>

          {showGuests && (
            <div className="absolute top-full right-0 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-8 z-50 animate-in fade-in slide-in-from-top-2 duration-200">
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-bold text-slate-800">Adults</h4>
                    <p className="text-xs text-slate-400">Ages 13 or above</p>
                  </div>
                  <div className="flex items-center space-x-4">
                    <button 
                      type="button"
                      onClick={() => updateGuests('adults', -1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      -
                    </button>
                    <span className="w-4 text-center font-bold">{params.adults}</span>
                    <button 
                      type="button"
                      onClick={() => updateGuests('adults', 1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      +
                    </button>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-bold text-slate-800">Children</h4>
                    <p className="text-xs text-slate-400">Ages 2 – 12</p>
                  </div>
                  <div className="flex items-center space-x-4">
                    <button 
                      type="button"
                      onClick={() => updateGuests('children', -1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      -
                    </button>
                    <span className="w-4 text-center font-bold">{params.children}</span>
                    <button 
                      type="button"
                      onClick={() => updateGuests('children', 1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      +
                    </button>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-bold text-slate-800">Infants</h4>
                    <p className="text-xs text-slate-400">Under 2 years</p>
                  </div>
                  <div className="flex items-center space-x-4">
                    <button 
                      type="button"
                      onClick={() => updateGuests('infants', -1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      -
                    </button>
                    <span className="w-4 text-center font-bold">{params.infants}</span>
                    <button 
                      type="button"
                      onClick={() => updateGuests('infants', 1)}
                      className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center hover:border-orange-500 hover:text-orange-500 transition-all active:scale-90"
                    >
                      +
                    </button>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-50 flex justify-between items-center">
                <button 
                  type="button"
                  onClick={() => setParams({ ...params, adults: 2, children: 0, infants: 0 })}
                  className="text-xs font-bold text-slate-400 hover:text-slate-600 transition-colors"
                >
                  Clear All
                </button>
                <button 
                  type="button"
                  onClick={() => setShowGuests(false)}
                  className="px-6 py-2 bg-slate-900 text-white text-xs font-bold rounded-xl hover:bg-slate-800 transition-all"
                >
                  Apply
                </button>
              </div>
            </div>
          )}
        </div>

        <button 
          type="submit"
          className="w-full lg:w-auto bg-orange-500 hover:bg-orange-600 text-white p-6 rounded-[1.5rem] shadow-xl shadow-orange-100 transition-all hover:-translate-y-1 active:scale-95 flex items-center justify-center"
