import { GoogleGenAI, Type } from "@google/genai";
import { Flight, FlightSearchParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function searchIndigoFlights(params: FlightSearchParams): Promise<Flight[]> {
  const prompt = `Act as the Indigo (6E) Developer API Flight Search Gateway. 
    Search for flights:
    From: ${params.origin}
    To: ${params.location}
    Date: ${params.startDate}
    Passengers: ${params.adults + params.children + params.infants}

    Return 4 to 6 realistic flight options in a valid JSON array format.
    Flight numbers must start with '6E'.
    Prices should be in INR (range 4000 to 18000).
    Include varied departure times throughout the day.
    Return an array of objects matching the Flight interface.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              flightNumber: { type: Type.STRING },
              origin: { type: Type.STRING },
              destination: { type: Type.STRING },
              departureTime: { type: Type.STRING },
              arrivalTime: { type: Type.STRING },
              duration: { type: Type.STRING },
              stops: { type: Type.NUMBER },
              price: { type: Type.NUMBER },
              tier: { 
                type: Type.STRING, 
                enum: ['Lite', 'Standard', 'Flexi Plus'] 
              }
            },
            required: ["id", "flightNumber", "origin", "destination", "departureTime", "arrivalTime", "duration", "stops", "price", "tier"]
          }
        }
      }
    });

    const text = response.text || "[]";
    return JSON.parse(text);
  } catch (error) {
    console.error("Indigo API Gateway Error:", error);
    return [];
  }
}

