    adults: 1,
    children: 0,
    infants: 0
  });

  const [vibe, setVibe] = useState<string>('');
  const [isTyping, setIsTyping] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState<'origin' | 'dest' | null>(null);
  const [showCalendar, setShowCalendar] = useState(false);
  const [showGuests, setShowGuests] = useState(false);
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const suggestionRef = useRef<HTMLDivElement>(null);
  const calendarRef = useRef<HTMLDivElement>(null);
  const guestsRef = useRef<HTMLDivElement>(null);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const isAtCurrentMonth = 
    currentMonth.getFullYear() === today.getFullYear() && 
    currentMonth.getMonth() === today.getMonth();

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      if (suggestionRef.current && !suggestionRef.current.contains(target)) {
        setShowSuggestions(null);
      }
      if (calendarRef.current && !calendarRef.current.contains(target)) {
        setShowCalendar(false);
      }
      if (guestsRef.current && !guestsRef.current.contains(target)) {
        setShowGuests(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const query = showSuggestions === 'origin' ? params.origin : params.location;
    if (!query) {
      setSuggestions([]);
      return;
    }

    const filtered = INDIAN_CITIES.filter(city => 
      city.toLowerCase().includes(query.toLowerCase())
    ).slice(0, 5);
    setSuggestions(filtered);

    if (showSuggestions === 'dest' && mode === 'experiences') {
      const timer = setTimeout(async () => {
        setIsTyping(false);
        const res = await getQuickSearchVibe(params.location);
        setVibe(res);
      }, 1000);
      setIsTyping(true);
      return () => clearTimeout(timer);
    }
  }, [params.location, params.origin, showSuggestions, mode]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'flights') {
      onFlightSearch(params);
    } else {
      onSearch(params);
    }
    setShowSuggestions(null);
    setShowCalendar(false);
    setShowGuests(false);
  };

  const selectSuggestion = (city: string) => {
    if (showSuggestions === 'origin') {
      setParams({ ...params, origin: city });
    } else {
      setParams({ ...params, location: city });
    }
    setShowSuggestions(null);
  };

  const formatDate = (date: Date) => date.toISOString().split('T')[0];

  const handleDateClick = (day: number) => {
    const clickedDate = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    clickedDate.setHours(0,0,0,0);
    if (clickedDate < today) return;

    const dateStr = formatDate(clickedDate);
    if (!params.startDate || (params.startDate && params.endDate)) {
      setParams({ ...params, startDate: dateStr, endDate: '' });
    } else {
      const start = new Date(params.startDate);
      if (clickedDate < start) {
        setParams({ ...params, startDate: dateStr, endDate: '' });
      } else {
        setParams({ ...params, endDate: dateStr });
        setShowCalendar(false);
      }
    }
  };

  const displayDateRange = () => {
    if (!params.startDate) return "Select dates";
    const start = new Date(params.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    if (!params.endDate) return `${start} - ...`;
    const end = new Date(params.endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    return `${start} - ${end}`;
  };

  return (
    <div className="w-full max-w-6xl mx-auto px-4 -mt-16 sm:-mt-20 lg:-mt-24 relative z-10">
      {/* Tab Switcher */}
      <div className="flex justify-center mb-4">
        <div className="bg-white/90 backdrop-blur-md p-1.5 rounded-2xl shadow-lg border border-slate-100 flex space-x-1">
          <button 
            type="button"
            onClick={() => setMode('experiences')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'experiences' ? 'bg-orange-500 text-white shadow-md' : 'text-slate-500 hover:text-orange-500'}`}
          >
            <Icons.Sparkles />
            <span>Experiences</span>
          </button>
          <button 
            type="button"
            onClick={() => setMode('flights')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'flights' ? 'bg-[#00316e] text-white shadow-md' : 'text-slate-500 hover:text-[#00316e]'}`}
          >
            <Icons.Plane />
            <span>Search Flights</span>
          </button>
        </div>
      </div>

      <form 
        onSubmit={handleSubmit}
        className="bg-white rounded-[2.5rem] shadow-2xl p-4 md:p-8 flex flex-col lg:flex-row items-center gap-6 border border-slate-100 relative"
      >
        {/* Origin (Only for Flights) */}
        {mode === 'flights' && (
          <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={suggestionRef}>
            <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-[#00316e]">
              <Icons.MapPin />
              <span>From</span>
            </label>
            <input 
              type="text"
              className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
              placeholder="Origin city"
              value={params.origin}
              onFocus={() => setShowSuggestions('origin')}
              onChange={(e) => setParams({...params, origin: e.target.value})}
            />
            {showSuggestions === 'origin' && suggestions.length > 0 && (
              <div className="absolute top-full left-0 w-full mt-4 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 z-50 animate-in fade-in slide-in-from-top-2">
                {suggestions.map((city, idx) => (
                  <button key={idx} type="button" onClick={() => selectSuggestion(city)} className="w-full px-6 py-3 text-left hover:bg-slate-50 flex items-center space-x-3 group">
                    <div className="p-2 bg-slate-50 rounded-lg text-slate-400 group-hover:bg-[#00316e]/10 group-hover:text-[#00316e]"><Icons.MapPin /></div>
                    <span className="text-slate-700 font-medium">{city}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        {mode === 'flights' && <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>}

        {/* Destination Section */}
        <div className="flex-[1.2] w-full flex flex-col space-y-2 relative" ref={suggestionRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Search />
            <span>{mode === 'flights' ? 'To' : 'Destination'}</span>
          </label>
          <input 
            type="text"
            className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
            placeholder="Where to?"
            value={params.location}
            onFocus={() => setShowSuggestions('dest')}
            onChange={(e) => setParams({...params, location: e.target.value})}
          />
          {showSuggestions === 'dest' && suggestions.length > 0 && (
            <div className="absolute top-full left-0 w-full mt-4 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 z-50 animate-in fade-in slide-in-from-top-2">
              {suggestions.map((city, idx) => (
                <button key={idx} type="button" onClick={() => selectSuggestion(city)} className="w-full px-6 py-3 text-left hover:bg-slate-50 flex items-center space-x-3 group">
                  <div className="p-2 bg-slate-50 rounded-lg text-slate-400 group-hover:bg-orange-100 group-hover:text-orange-600"><Icons.MapPin /></div>
                  <span className="text-slate-700 font-medium">{city}</span>
                </button>
              ))}
            </div>
          )}
          <div className="h-4 overflow-hidden">
             {mode === 'experiences' && vibe && !isTyping && showSuggestions !== 'dest' && (
               <p className="text-[10px] text-orange-600 font-medium italic animate-in slide-in-from-top-2">{vibe}</p>
             )}
          </div>
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        {/* Dates */}
        <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={calendarRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Calendar />
            <span>Travel Window</span>
          </label>
          <button type="button" onClick={() => setShowCalendar(!showCalendar)} className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 truncate">
            {displayDateRange()}
          </button>
          {showCalendar && (
            <div className="absolute top-full left-0 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-6 z-50 animate-in fade-in slide-in-from-top-2">
              <div className="flex justify-between items-center mb-4">
                <button type="button" disabled={isAtCurrentMonth} onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))} className={`p-2 rounded-full ${isAtCurrentMonth ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-50'}`}>
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg>
                </button>
                <span className="font-bold text-slate-800">{currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</span>
                <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))} className="p-2 text-slate-600 hover:bg-slate-50 rounded-full">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                </button>
              </div>
              <div className="grid grid-cols-7 gap-1">
                {['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'].map(d => <span key={d} className="text-[10px] font-bold text-slate-300 text-center uppercase">{d}</span>)}
                {Array.from({ length: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay() }).map((_, i) => <div key={i} />)}
                {Array.from({ length: new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate() }).map((_, i) => {
                  const d = i + 1;
                  const dateObj = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), d);
                  const disabled = dateObj < today;
                  const selected = formatDate(dateObj) === params.startDate || formatDate(dateObj) === params.endDate;
                  return (
                    <button key={d} type="button" disabled={disabled} onClick={() => handleDateClick(d)} className={`h-8 w-8 text-xs font-semibold rounded-full ${selected ? 'bg-orange-500 text-white' : disabled ? 'text-slate-200' : 'hover:bg-orange-50 text-slate-600'}`}>
                      {d}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

        {/* Travelers */}
        <div className="w-full lg:w-48 flex flex-col space-y-2 relative" ref={guestsRef}>
          <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
            <Icons.Users />
            <span>Travelers</span>
          </label>
          <button type="button" onClick={() => setShowGuests(!showGuests)} className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 truncate">
             {params.adults + params.children + params.infants} {params.adults + params.children + params.infants === 1 ? 'Traveler' : 'Travelers'}
          </button>
          {showGuests && (
            <div className="absolute top-full right-0 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-8 z-50">
              {['adults', 'children', 'infants'].map((type) => (
                <div key={type} className="flex items-center justify-between mb-4">
                  <div>
                    <h4 className="font-bold text-slate-800 capitalize">{type}</h4>
                    <p className="text-[10px] text-slate-400">{type === 'adults' ? '13+ yrs' : type === 'children' ? '2-12 yrs' : 'Under 2'}</p>
                  </div>
                  <div className="flex items-center space-x-4">
                    <button type="button" onClick={() => setParams({...params, [type]: Math.max(type === 'adults' ? 1 : 0, params[type as keyof FlightSearchParams] as number - 1)})} className="w-8 h-8 rounded-full border flex items-center justify-center">-</button>
                    <span className="font-bold">{params[type as keyof FlightSearchParams]}</span>
                    <button type="button" onClick={() => setParams({...params, [type]: (params[type as keyof FlightSearchParams] as number) + 1})} className="w-8 h-8 rounded-full border flex items-center justify-center">+</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <button 
          type="submit"
          className={`w-full lg:w-auto p-6 rounded-[1.5rem] shadow-xl text-white transition-all hover:-translate-y-1 ${mode === 'flights' ? 'bg-[#00316e] shadow-[#00316e]/20' : 'bg-orange-500 shadow-orange-100'}`}
        >
          <Icons.Search />
        </button>
      </form>
    </div>
  );
};

export default SearchForm;

import React, { useState } from 'react';
import { User, SearchParams, FlightSearchParams, TripSuggestion, Flight } from './types';
import Navbar from './components/Navbar';
import SearchForm from './components/SearchForm';
import DestinationCard from './components/DestinationCard';
import LoginModal from './components/LoginModal';
import { FEATURED_DESTINATIONS, Icons } from './constants';
import { getTravelSuggestions } from './services/geminiService';
import { searchIndigoFlights, searchAirIndiaFlights } from './services/flightService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [searchResult, setSearchResult] = useState<TripSuggestion | null>(null);
  const [flights, setFlights] = useState<Flight[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchType, setSearchType] = useState<'experiences' | 'flights'>('experiences');

  const handleLogin = (name: string, email: string) => {
    setUser({ name, email });
    setShowLogin(false);
  };

  const handleSearch = async (params: SearchParams) => {
    setSearchType('experiences');
    setIsSearching(true);
    const suggestion = await getTravelSuggestions(params);
    setSearchResult(suggestion);
    setFlights([]);
    setIsSearching(false);
    scrollToResults();
  };

  const handleFlightSearch = async (params: FlightSearchParams) => {
    setSearchType('flights');
    setIsSearching(true);

    // Fetch from both Indigo and Air India concurrently
    const [indigoResults, airIndiaResults] = await Promise.all([
      searchIndigoFlights(params),
      searchAirIndiaFlights(params)
    ]);

    // Combine and sort by price ascending
    const combined = [...indigoResults, ...airIndiaResults].sort((a, b) => a.price - b.price);

    setFlights(combined);
    setSearchResult(null);
    setIsSearching(false);
    scrollToResults();
  };

  const scrollToResults = () => {
    setTimeout(() => {
      document.getElementById('search-results')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar user={user} onLoginClick={() => setShowLogin(true)} onLogout={() => setUser(null)} />

      {/* Hero */}
      <section className="relative pt-32 pb-20 md:pt-48 md:pb-32 overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-orange-50 to-transparent -z-10 blur-3xl opacity-50"></div>
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-white shadow-sm text-slate-600 mb-8 border border-slate-100">
            <Icons.Sparkles />
            <span className="text-xs font-bold uppercase tracking-widest">Premium AI Travel Experiences</span>
          </div>
          <h1 className="text-5xl md:text-8xl font-serif font-bold text-slate-900 mb-8 tracking-tighter leading-[0.9]">
            Beyond the <br />
            <span className="bg-gradient-to-r from-orange-500 to-amber-600 bg-clip-text text-transparent italic">Horizon.</span>
          </h1>
        </div>
      </section>

      <SearchForm onSearch={handleSearch} onFlightSearch={handleFlightSearch} />

      {/* Results Section */}
      <section id="search-results" className="max-w-7xl mx-auto px-4 py-24 min-h-[400px]">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-24 animate-in fade-in duration-500">
            <div className={`w-16 h-16 border-4 ${searchType === 'flights' ? 'border-[#00316e]/20 border-t-[#00316e]' : 'border-orange-500/20 border-t-orange-500'} rounded-full animate-spin mb-6`}></div>
            <h3 className="text-2xl font-serif text-slate-800">
              {searchType === 'flights' ? 'Synchronizing Airline Developer APIs...' : 'AI is planning your escape...'}
            </h3>
            {searchType === 'flights' && <p className="text-slate-400 mt-2">Fetching Indigo (6E) & Air India (AI) schedules</p>}
          </div>
        )}

        {/* Flight Results */}
        {!isSearching && flights.length > 0 && (
          <div className="animate-in slide-in-from-bottom-8 duration-700">
            <div className="flex items-center justify-between mb-12">
              <div>
                <h2 className="text-4xl font-serif font-bold text-slate-900">Direct Flights</h2>
                <p className="text-slate-500 mt-2">Best fares sorted by price from our airline partners</p>
              </div>
              <div className="flex space-x-2">
                <div className="bg-[#00316e] text-white px-4 py-2 rounded-lg text-xs font-bold tracking-widest uppercase">
                  Indigo
                </div>
                <div className="bg-red-600 text-white px-4 py-2 rounded-lg text-xs font-bold tracking-widest uppercase">
                  Air India
                </div>
              </div>
            </div>
            <div className="space-y-4">
              {flights.map(flight => (
                <div key={flight.id} className="bg-white rounded-3xl p-6 md:p-10 border border-slate-100 shadow-sm hover:shadow-xl transition-all flex flex-col md:flex-row items-center gap-8 group">
                  <div className="flex flex-col items-center justify-center space-y-2 min-w-[120px]">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${flight.airline === 'Indigo' ? 'bg-slate-50 text-[#00316e] group-hover:bg-[#00316e] group-hover:text-white' : 'bg-red-50 text-red-600 group-hover:bg-red-600 group-hover:text-white'}`}>
                      <Icons.Plane />
                    </div>
                    <span className="font-bold text-slate-800">{flight.flightNumber}</span>
                    <span className={`text-[10px] font-bold uppercase tracking-widest ${flight.airline === 'Indigo' ? 'text-[#00316e]' : 'text-red-600'}`}>{flight.airline}</span>
                  </div>

                  <div className="flex-1 grid grid-cols-3 items-center text-center">
                    <div>
                      <div className="text-2xl font-bold text-slate-900">{flight.departureTime}</div>
                      <div className="text-xs font-bold text-slate-400 uppercase">{flight.origin}</div>
                    </div>
                    <div className="relative px-8">
                       <div className="h-px bg-slate-200 w-full relative">
                         <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white px-2 text-[10px] font-bold text-slate-400">
                           {flight.duration}
                         </div>
                       </div>
                       <p className="text-[10px] mt-2 text-slate-400 font-bold uppercase tracking-widest">
                         {flight.stops === 0 ? 'Non-stop' : `${flight.stops} Stop`}
                       </p>
                    </div>
                    <div>
                      <div className="text-2xl font-bold text-slate-900">{flight.arrivalTime}</div>
                      <div className="text-xs font-bold text-slate-400 uppercase">{flight.destination}</div>
                    </div>
                  </div>

                  <div className="flex flex-col items-end space-y-1">
                    <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded-full ${flight.tier === 'Business' ? 'bg-amber-100 text-amber-700' : 'bg-green-50 text-green-600'}`}>
                      {flight.tier}
                    </span>
                    <div className="text-3xl font-bold text-slate-900">₹{flight.price.toLocaleString()}</div>
                    <button className={`text-white px-8 py-3 rounded-2xl text-sm font-bold transition-all active:scale-95 shadow-lg ${flight.airline === 'Indigo' ? 'bg-[#00316e] hover:bg-slate-900 shadow-[#00316e]/20' : 'bg-red-600 hover:bg-red-700 shadow-red-200'}`}>
                      Select
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* AI Experiences Results */}
        {!isSearching && searchResult && (
          <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-[3rem] p-8 md:p-16 text-white shadow-2xl relative overflow-hidden animate-in zoom-in-95 duration-700">
             <div className="relative z-10 grid md:grid-cols-2 gap-16 items-center">
                <div>
                  <h2 className="text-4xl md:text-6xl font-serif font-bold mb-8 leading-tight">{searchResult.title}</h2>
                  <div className="space-y-6">
                    <div className="flex items-start space-x-4">
                      <div className="bg-white/10 p-2 rounded-lg text-orange-400"><Icons.Sparkles /></div>
                      <div><h4 className="text-lg font-bold">The Vibe</h4><p className="text-slate-300">{searchResult.vibe}</p></div>
                    </div>
                    <div className="flex items-start space-x-4">
                      <div className="bg-white/10 p-2 rounded-lg text-orange-400"><Icons.Calendar /></div>
                      <div><h4 className="text-lg font-bold">Best Time</h4><p className="text-slate-300">{searchResult.bestTime}</p></div>
                    </div>
                  </div>
                </div>
                <div className="bg-white/5 backdrop-blur-md rounded-3xl p-8 border border-white/10">
                  <h3 className="text-2xl font-serif font-bold mb-6">Highlights</h3>
                  <ul className="space-y-4">
                    {searchResult.highlights.map((h, i) => (
                      <li key={i} className="flex items-center space-x-4"><div className="h-2 w-2 rounded-full bg-orange-500"></div><span className="text-slate-100">{h}</span></li>
                    ))}
                  </ul>
                  <button className="w-full mt-10 py-4 bg-orange-500 text-white rounded-2xl font-bold hover:bg-orange-600 shadow-xl shadow-orange-900/40">Build Full Itinerary</button>
                </div>
             </div>
          </div>
        )}
      </section>

      {/* Featured */}
      <section className="max-w-7xl mx-auto px-4 pb-24">
        <h2 className="text-4xl font-serif font-bold text-slate-900 mb-12">Handpicked Destinations</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {FEATURED_DESTINATIONS.map(d => <DestinationCard key={d.id} destination={d} />)}
        </div>
      </section>

      {showLogin && <LoginModal onClose={() => setShowLogin(false)} onLogin={handleLogin} />}
    </div>
  );
};

export default App;

export interface Destination {
  id: string;
  name: string;
  country: string;
  description: string;
  price: number;
  rating: number;
  imageUrl: string;
  category: 'adventure' | 'beach' | 'city' | 'nature';
}

export interface SearchParams {
  location: string;
  startDate: string;
  endDate: string;
  adults: number;
  children: number;
  childrenAges: number[];
  infants: number;
}

