import { GoogleGenAI, Type } from "@google/genai";
import { Hotel, SearchParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function searchPremiumHotels(params: SearchParams): Promise<Hotel[]> {
  const prompt = `Act as a luxury hotel booking engine API. Search for high-end luxury hotels in:
    Location: ${params.location}
    Guests: ${params.adults} adults, ${params.children} children

    Return 3 to 5 realistic luxury hotel options in JSON array format.
    Prices should be in INR per night (range 8000 to 45000).
    Include varied amenities and high-end descriptions.
    Set brand field to "Premium".
    Return an array of objects matching the Hotel interface.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              location: { type: Type.STRING },
              price: { type: Type.NUMBER },
              rating: { type: Type.NUMBER },
              imageUrl: { type: Type.STRING },
              description: { type: Type.STRING },
              brand: { type: Type.STRING, enum: ["Premium"] }
            },
            required: ["id", "name", "location", "price", "rating", "imageUrl", "description", "brand"]
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Premium Hotel API Error:", error);
    return [];
  }
}

export async function searchOyoHotels(params: SearchParams): Promise<Hotel[]> {
  const prompt = `Act as the OYO Developer API (v2.1) Hotel Inventory Gateway.
    Search for budget and mid-range hotels in:
    Location: ${params.location}
    Check-in: ${params.startDate}
    Check-out: ${params.endDate}
    Guests: ${params.adults} Adults, ${params.children} Children

    Return 5 to 8 realistic OYO hotel options in JSON array format.
    Use OYO brand categories: 'OYO Townhouse', 'OYO Flagship', 'Capital O', 'Spot On', 'SilverKey'.
    Prices should be in INR per night (range 800 to 5500).
    Descriptions should be concise and mention OYO standard amenities like free Wi-Fi, AC, and clean linen.
    Set brand field to "Oyo".
    Return an array of objects matching the Hotel interface.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              location: { type: Type.STRING },
              price: { type: Type.NUMBER },
              rating: { type: Type.NUMBER },
              imageUrl: { type: Type.STRING },
              description: { type: Type.STRING },
              brand: { type: Type.STRING, enum: ["Oyo"] },
              category: { type: Type.STRING }
            },
            required: ["id", "name", "location", "price", "rating", "imageUrl", "description", "brand"]
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("OYO API Error:", error);
    return [];
  }
}

