import { GoogleGenAI, Type } from "@google/genai";
import { SearchParams, TripSuggestion, FlightSearchParams } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getTravelSuggestions(params: SearchParams): Promise<TripSuggestion> {
  const totalGuests = params.adults + params.children + params.infants;
  const prompt = `Act as a luxury travel concierge. Create a unique trip summary for:
    Location: ${params.location}
    Travelers: ${totalGuests} total (${params.adults} adults, ${params.children} children, ${params.infants} infants under 2 years).
    Duration: From ${params.startDate} to ${params.endDate}.
    Provide insights in a luxurious, inviting tone. Consider family-friendly recommendations if children or infants are included.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            highlights: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            vibe: { type: Type.STRING },
            bestTime: { type: Type.STRING }
          },
          required: ["title", "highlights", "vibe", "bestTime"]
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      title: "Exploring " + params.location,
      highlights: ["Local Cuisine", "Historic Landmarks", "Cultural Immersion"],
      vibe: "Elegant and adventurous",
      bestTime: "Late spring or early autumn"
    };
  }
}

export async function parseFlightQuery(query: string): Promise<Partial<FlightSearchParams>> {
  const today = new Date().toISOString().split('T')[0];
  const prompt = `Extract flight search parameters from this natural language query: "${query}".
    Today's date is ${today}.
    Rules:
    - If origin is missing, default to "Mumbai".
    - If date is relative (e.g. "tomorrow", "next Friday"), calculate the exact YYYY-MM-DD.
    - If return date isn't mentioned, set tripType to "one-way".
    - Passengers defaults to 1 adult if not mentioned.
    Return JSON only.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            origin: { type: Type.STRING },
            location: { type: Type.STRING, description: "The destination city" },
            startDate: { type: Type.STRING, description: "YYYY-MM-DD" },
            endDate: { type: Type.STRING, description: "YYYY-MM-DD (optional)" },
            adults: { type: Type.NUMBER },
            children: { type: Type.NUMBER },
            infants: { type: Type.NUMBER },
            tripType: { type: Type.STRING, enum: ["one-way", "return"] }
          },
          required: ["origin", "location", "startDate", "tripType"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Flight Parsing Error:", error);
    return { origin: "Mumbai", location: "Delhi", startDate: today, tripType: "one-way", adults: 1 };
  }
}

export async function getQuickSearchVibe(query: string): Promise<string> {
