    contents: `Describe the 'vibe' of traveling to ${query} in exactly one short, evocative sentence.`,
  });
  return response.text || "A mysterious and enchanting journey awaits.";
}

import React, { useState, useEffect, useRef } from 'react';
import { Icons, INDIAN_CITIES } from '../constants';
import { SearchParams, FlightSearchParams } from '../types';

interface SearchFormProps {
  onHotelSearch: (params: SearchParams) => void;
  onFlightSearch: (params: FlightSearchParams) => void;
  onPackageSearch: (params: SearchParams) => void;
  onAIFlightSearch: (query: string) => void;
}

const SearchForm: React.FC<SearchFormProps> = ({ onHotelSearch, onFlightSearch, onPackageSearch, onAIFlightSearch }) => {
  const [activeTab, setActiveTab] = useState<'hotels' | 'flights' | 'packages'>('hotels');
  const [flightMode, setFlightMode] = useState<'form' | 'ai'>('form');
  const [flightType, setFlightType] = useState<'one-way' | 'return'>('return');
  const [aiQuery, setAiQuery] = useState('');

  const [params, setParams] = useState<FlightSearchParams>({
    location: '',
    origin: 'Mumbai',
    startDate: '',
    endDate: '',
    adults: 1,
    children: 0,
    childrenAges: [],
    infants: 0,
    tripType: 'return'
  });

  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState<'origin' | 'dest' | null>(null);
  const [showCalendar, setShowCalendar] = useState(false);
  const [showGuests, setShowGuests] = useState(false);
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const suggestionRef = useRef<HTMLDivElement>(null);
  const calendarRef = useRef<HTMLDivElement>(null);
  const guestsRef = useRef<HTMLDivElement>(null);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const isAtCurrentMonth = 
    currentMonth.getFullYear() === today.getFullYear() && 
    currentMonth.getMonth() === today.getMonth();

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      if (suggestionRef.current && !suggestionRef.current.contains(target)) setShowSuggestions(null);
      if (calendarRef.current && !calendarRef.current.contains(target)) setShowCalendar(false);
      if (guestsRef.current && !guestsRef.current.contains(target)) setShowGuests(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const query = showSuggestions === 'origin' ? params.origin : params.location;
    if (!query) {
      setSuggestions([]);
      return;
    }
    const filtered = INDIAN_CITIES.filter(city => 
      city.toLowerCase().includes(query.toLowerCase())
    ).slice(0, 5);
    setSuggestions(filtered);
  }, [params.location, params.origin, showSuggestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'flights' && flightMode === 'ai') {
      if (aiQuery.trim()) onAIFlightSearch(aiQuery);
      return;
    }

    if (activeTab === 'hotels') onHotelSearch(params);
    else if (activeTab === 'flights') onFlightSearch({ ...params, tripType: flightType });
    else onPackageSearch(params);

    setShowSuggestions(null);
    setShowCalendar(false);
    setShowGuests(false);
  };

  const handleChildCountChange = (delta: number) => {
    const newCount = Math.max(0, params.children + delta);
    let newAges = [...params.childrenAges];
    if (delta > 0) {
      newAges.push(5);
    } else if (delta < 0) {
      newAges.pop();
    }
    setParams({ ...params, children: newCount, childrenAges: newAges });
  };

  const handleChildAgeChange = (index: number, age: number) => {
    const newAges = [...params.childrenAges];
    newAges[index] = age;
    setParams({ ...params, childrenAges: newAges });
  };

  const formatDate = (date: Date) => date.toISOString().split('T')[0];

  const handleDateClick = (day: number) => {
    const clickedDate = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    clickedDate.setHours(0,0,0,0);
    if (clickedDate < today) return;

    const dateStr = formatDate(clickedDate);
    if (activeTab === 'flights' && flightType === 'one-way') {
      setParams({ ...params, startDate: dateStr, endDate: '' });
      setShowCalendar(false);
      return;
    }

    if (!params.startDate || (params.startDate && params.endDate)) {
      setParams({ ...params, startDate: dateStr, endDate: '' });
    } else {
      const start = new Date(params.startDate);
      if (clickedDate < start) {
        setParams({ ...params, startDate: dateStr, endDate: '' });
      } else {
        setParams({ ...params, endDate: dateStr });
        setShowCalendar(false);
      }
    }
  };

  const displayDateRange = () => {
    if (!params.startDate) return "Select dates";
    const start = new Date(params.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    if (activeTab === 'flights' && flightType === 'one-way') return start;
    if (!params.endDate) return `${start} - ...`;
    const end = new Date(params.endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    return `${start} - ${end}`;
  };

  return (
    <div className="w-full max-w-6xl mx-auto px-4 -mt-16 sm:-mt-20 lg:-mt-24 relative z-10">
      {/* Main Tab Switcher */}
      <div className="flex justify-center mb-4">
        <div className="bg-white/90 backdrop-blur-md p-1.5 rounded-2xl shadow-lg border border-slate-100 flex space-x-1">
          {[
            { id: 'hotels', label: 'Hotels', icon: <Icons.Search /> },
            { id: 'flights', label: 'Flights', icon: <Icons.Plane /> },
            { id: 'packages', label: 'Packages', icon: <Icons.Sparkles /> }
          ].map((tab) => (
            <button 
              key={tab.id}
              type="button"
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === tab.id ? 'bg-orange-500 text-white shadow-md' : 'text-slate-500 hover:text-orange-500'}`}
            >
              {tab.icon}
              <span>{tab.label}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-2xl p-4 md:p-8 border border-slate-100 relative">
        {/* Flight Mode Switcher */}
        {activeTab === 'flights' && (
          <div className="flex justify-between items-center mb-6 px-2">
            <div className="flex space-x-6">
              <button 
                type="button" 
                onClick={() => setFlightType('one-way')}
                className={`text-sm font-bold flex items-center space-x-2 transition-colors ${flightType === 'one-way' && flightMode === 'form' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${flightType === 'one-way' && flightMode === 'form' ? 'border-orange-500' : 'border-slate-300'}`}>
                  {flightType === 'one-way' && flightMode === 'form' && <div className="w-2 h-2 rounded-full bg-orange-500" />}
                </div>
                <span>One-way</span>
              </button>
              <button 
                type="button" 
                onClick={() => setFlightType('return')}
                className={`text-sm font-bold flex items-center space-x-2 transition-colors ${flightType === 'return' && flightMode === 'form' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${flightType === 'return' && flightMode === 'form' ? 'border-orange-500' : 'border-slate-300'}`}>
                  {flightType === 'return' && flightMode === 'form' && <div className="w-2 h-2 rounded-full bg-orange-500" />}
                </div>
                <span>Return trip</span>
              </button>
            </div>

            <button 
              type="button"
              onClick={() => setFlightMode(flightMode === 'form' ? 'ai' : 'form')}
              className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all border ${flightMode === 'ai' ? 'bg-orange-50 border-orange-200 text-orange-600 shadow-sm' : 'border-slate-100 text-slate-400 hover:border-orange-100 hover:text-orange-500'}`}
            >
              <Icons.Sparkles />
              <span>{flightMode === 'ai' ? 'Switch to Manual Form' : 'Try AI Assistant Search'}</span>
            </button>
          </div>
        )}

        {flightMode === 'ai' && activeTab === 'flights' ? (
          /* AI Assistant Search Bar */
          <form onSubmit={handleSubmit} className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-orange-500 to-amber-500 rounded-2xl blur opacity-20 group-focus-within:opacity-40 transition duration-500"></div>
            <div className="relative flex items-center bg-white rounded-2xl border border-slate-100 p-2 shadow-sm">
              <div className="pl-6 pr-4 text-orange-500">
                <Icons.Sparkles />
              </div>
              <input 
                type="text"
                className="w-full py-4 text-lg font-medium text-slate-800 placeholder-slate-300 bg-transparent border-none focus:ring-0 outline-none"
                placeholder="Ask me like: 'Flights from Mumbai to Goa for 2 people next Monday'..."
                value={aiQuery}
                onChange={(e) => setAiQuery(e.target.value)}
              />
              <button 
                type="submit"
                className="ml-4 px-8 py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all active:scale-95 shadow-lg flex items-center space-x-2"
              >
                <span>Search</span>
                <Icons.ChevronRight />
              </button>
            </div>
          </form>
        ) : (
          /* Guided Form */
          <form onSubmit={handleSubmit} className="flex flex-col lg:flex-row items-center gap-6">
            {activeTab === 'flights' && (
              <>
                <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={suggestionRef}>
                  <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
                    <Icons.MapPin />
                    <span>From</span>
                  </label>
                  <input 
                    type="text"
                    className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
                    placeholder="Origin city"
                    value={params.origin}
                    onFocus={() => setShowSuggestions('origin')}
                    onChange={(e) => setParams({...params, origin: e.target.value})}
                  />
                  {showSuggestions === 'origin' && suggestions.length > 0 && (
                    <div className="absolute top-full left-0 w-full mt-4 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 z-50">
                      {suggestions.map((city, idx) => (
                        <button key={idx} type="button" onClick={() => { setParams({...params, origin: city}); setShowSuggestions(null); }} className="w-full px-6 py-3 text-left hover:bg-slate-50 flex items-center space-x-3">
                          <Icons.MapPin /> <span className="text-slate-700 font-medium">{city}</span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
                <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>
              </>
            )}

            <div className="flex-[1.2] w-full flex flex-col space-y-2 relative" ref={suggestionRef}>
              <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
                <Icons.Search />
                <span>{activeTab === 'hotels' ? 'Hotel in India' : activeTab === 'flights' ? 'To' : 'Destination'}</span>
              </label>
              <input 
                type="text"
                className="w-full px-0 py-2 text-xl font-medium border-none focus:ring-0 outline-none text-slate-800 bg-transparent placeholder-slate-300"
                placeholder="City or Hotel"
                value={params.location}
                onFocus={() => setShowSuggestions('dest')}
                onChange={(e) => setParams({...params, location: e.target.value})}
              />
              {showSuggestions === 'dest' && suggestions.length > 0 && (
                <div className="absolute top-full left-0 w-full mt-4 bg-white rounded-2xl shadow-2xl border border-slate-100 py-2 z-50">
                  {suggestions.map((city, idx) => (
                    <button key={idx} type="button" onClick={() => { setParams({...params, location: city}); setShowSuggestions(null); }} className="w-full px-6 py-3 text-left hover:bg-slate-50 flex items-center space-x-3">
                      <Icons.MapPin /> <span className="text-slate-700 font-medium">{city}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

            <div className="flex-1 w-full flex flex-col space-y-2 relative" ref={calendarRef}>
              <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
                <Icons.Calendar />
                <span>{activeTab === 'flights' && flightType === 'one-way' ? 'Departure' : 'Stay Window'}</span>
              </label>
              <button type="button" onClick={() => setShowCalendar(!showCalendar)} className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 truncate">
                {displayDateRange()}
              </button>
              {showCalendar && (
                <div className="absolute top-full left-0 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-6 z-50">
                  <div className="flex justify-between items-center mb-4">
                    <button type="button" disabled={isAtCurrentMonth} onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))} className={`p-2 rounded-full ${isAtCurrentMonth ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-50'}`}>
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg>
                    </button>
                    <span className="font-bold text-slate-800">{currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</span>
                    <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))} className="p-2 text-slate-600 hover:bg-slate-50 rounded-full">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                    </button>
                  </div>
                  <div className="grid grid-cols-7 gap-1">
                    {['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'].map(d => <span key={d} className="text-[10px] font-bold text-slate-300 text-center uppercase">{d}</span>)}
                    {Array.from({ length: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay() }).map((_, i) => <div key={i} />)}
                    {Array.from({ length: new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate() }).map((_, i) => {
                      const d = i + 1;
                      const dateObj = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), d);
                      const disabled = dateObj < today;
                      const selected = formatDate(dateObj) === params.startDate || formatDate(dateObj) === params.endDate;
                      return (
                        <button key={d} type="button" disabled={disabled} onClick={() => handleDateClick(d)} className={`h-8 w-8 text-xs font-semibold rounded-full ${selected ? 'bg-orange-500 text-white' : disabled ? 'text-slate-200' : 'hover:bg-orange-50 text-slate-600'}`}>
                          {d}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>

            <div className="h-px lg:h-12 w-full lg:w-px bg-slate-100"></div>

            <div className="w-full lg:w-48 flex flex-col space-y-2 relative" ref={guestsRef}>
              <label className="flex items-center space-x-2 text-xs font-bold uppercase tracking-widest text-slate-400">
                <Icons.Users />
                <span>Travelers</span>
              </label>
              <button type="button" onClick={() => setShowGuests(!showGuests)} className="w-full px-0 py-2 text-xl font-medium text-left text-slate-800 truncate">
                 {params.adults + params.children + params.infants} {params.adults + params.children + params.infants === 1 ? 'Traveler' : 'Travelers'}
              </button>
              {showGuests && (
                <div className="absolute top-full right-0 w-80 bg-white rounded-[2rem] shadow-2xl border border-slate-100 p-8 z-50 max-h-[400px] overflow-y-auto">
                  <div className="space-y-6">
                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="font-bold text-slate-800">Adults</h4>
                        <p className="text-[10px] text-slate-400">12+ years</p>
                      </div>
                      <div className="flex items-center space-x-4">
                        <button type="button" onClick={() => setParams({...params, adults: Math.max(1, params.adults - 1)})} className="w-8 h-8 rounded-full border flex items-center justify-center">-</button>
                        <span className="font-bold">{params.adults}</span>
                        <button type="button" onClick={() => setParams({...params, adults: params.adults + 1})} className="w-8 h-8 rounded-full border flex items-center justify-center">+</button>
                      </div>
                    </div>

                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="font-bold text-slate-800">Children</h4>
                        <p className="text-[10px] text-slate-400">2-11 years</p>
                      </div>
                      <div className="flex items-center space-x-4">
                        <button type="button" onClick={() => handleChildCountChange(-1)} className="w-8 h-8 rounded-full border flex items-center justify-center">-</button>
                        <span className="font-bold">{params.children}</span>
                        <button type="button" onClick={() => handleChildCountChange(1)} className="w-8 h-8 rounded-full border flex items-center justify-center">+</button>
                      </div>
                    </div>

                    {params.children > 0 && (
                      <div className="pt-4 border-t border-slate-50 space-y-4">
                        <h5 className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Ages of children</h5>
                        <div className="grid grid-cols-2 gap-3">
                          {params.childrenAges.map((age, idx) => (
                            <div key={idx} className="flex flex-col space-y-1">
                              <label className="text-[10px] text-slate-500">Child {idx + 1}</label>
                              <select 
                                value={age}
                                onChange={(e) => handleChildAgeChange(idx, parseInt(e.target.value))}
                                className="w-full bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 text-xs outline-none focus:ring-1 focus:ring-orange-500"
                              >
                                {Array.from({ length: 12 }).map((_, i) => (
                                  <option key={i} value={i}>{i} years</option>
                                ))}
                              </select>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="font-bold text-slate-800">Infants</h4>
                        <p className="text-[10px] text-slate-400">Under 2 years</p>
                      </div>
                      <div className="flex items-center space-x-4">
                        <button type="button" onClick={() => setParams({...params, infants: Math.max(0, params.infants - 1)})} className="w-8 h-8 rounded-full border flex items-center justify-center">-</button>
                        <span className="font-bold">{params.infants}</span>
                        <button type="button" onClick={() => setParams({...params, infants: params.infants + 1})} className="w-8 h-8 rounded-full border flex items-center justify-center">+</button>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <button 
              type="submit"
              className={`w-full lg:w-auto p-6 rounded-[1.5rem] shadow-xl text-white transition-all hover:-translate-y-1 bg-orange-500 shadow-orange-100`}
            >
              <Icons.Search />
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default SearchForm;

import React, { useState } from 'react';
import { User, SearchParams, FlightSearchParams, TripSuggestion, Flight, Hotel, TravelPackage } from './types';
import Navbar from './components/Navbar';
import SearchForm from './components/SearchForm';
import DestinationCard from './components/DestinationCard';
import LoginModal from './components/LoginModal';
import { FEATURED_DESTINATIONS, Icons } from './constants';
import { getTravelSuggestions, parseFlightQuery } from './services/geminiService';
import { searchIndigoFlights, searchAirIndiaFlights } from './services/flightService';
import { searchPremiumHotels, searchOyoHotels } from './services/hotelService';
import { searchTboHotels, searchTboPackages } from './services/tboService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [searchResult, setSearchResult] = useState<TripSuggestion | null>(null);
  const [flights, setFlights] = useState<Flight[]>([]);
  const [hotels, setHotels] = useState<Hotel[]>([]);
  const [packages, setPackages] = useState<TravelPackage[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchType, setSearchType] = useState<'hotels' | 'flights' | 'packages'>('hotels');

  const handleLogin = (name: string, email: string) => {
    setUser({ name, email });
    setShowLogin(false);
  };

  const handleHotelSearch = async (params: SearchParams) => {
    setSearchType('hotels');
    setIsSearching(true);
    setFlights([]);
    setPackages([]);
    setSearchResult(null);

    const [premiumResults, oyoResults, tboResults] = await Promise.all([
      searchPremiumHotels(params),
      searchOyoHotels(params),
      searchTboHotels(params)
    ]);

    const combined = [...premiumResults, ...oyoResults, ...tboResults].sort((a, b) => a.price - b.price);

    setHotels(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handleFlightSearch = async (params: FlightSearchParams) => {
    setSearchType('flights');
    setIsSearching(true);
    setHotels([]);
    setPackages([]);
    setSearchResult(null);
    const [indigoResults, airIndiaResults] = await Promise.all([
      searchIndigoFlights(params),
      searchAirIndiaFlights(params)
    ]);

    // Low to high price sorting
    const combined = [...indigoResults, ...airIndiaResults].sort((a, b) => a.price - b.price);

    setFlights(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handleAIFlightSearch = async (query: string) => {
    setSearchType('flights');
    setIsSearching(true);
    setHotels([]);
    setPackages([]);
    setFlights([]);

    // 1. Use Gemini to parse the natural language query
    const parsedParams = await parseFlightQuery(query);

    // 2. Perform the structured search
    const searchParams: FlightSearchParams = {
      location: parsedParams.location || 'Delhi',
      origin: parsedParams.origin || 'Mumbai',
      startDate: parsedParams.startDate || new Date().toISOString().split('T')[0],
      endDate: parsedParams.endDate || '',
      adults: parsedParams.adults || 1,
      children: parsedParams.children || 0,
      infants: parsedParams.infants || 0,
      childrenAges: [],
      tripType: parsedParams.tripType as any || 'one-way'
    };

    const [indigoResults, airIndiaResults] = await Promise.all([
      searchIndigoFlights(searchParams),
      searchAirIndiaFlights(searchParams)
    ]);

    // 3. Low to high price sorting
    const combined = [...indigoResults, ...airIndiaResults].sort((a, b) => a.price - b.price);

    setFlights(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handlePackageSearch = async (params: SearchParams) => {
    setSearchType('packages');
    setIsSearching(true);
    setHotels([]);
    setFlights([]);

    const [tboPackages, aiSuggestion] = await Promise.all([
      searchTboPackages(params),
      getTravelSuggestions(params)
    ]);

    setPackages(tboPackages);
    setSearchResult(aiSuggestion);
    setIsSearching(false);
    scrollToResults();
  };

  const scrollToResults = () => {
    setTimeout(() => {
      document.getElementById('search-results')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar user={user} onLoginClick={() => setShowLogin(true)} onLogout={() => setUser(null)} />

      {/* Hero */}
      <section className="relative pt-32 pb-20 md:pt-48 md:pb-32 overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-orange-50 to-transparent -z-10 blur-3xl opacity-50"></div>
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-white shadow-sm text-slate-600 mb-8 border border-slate-100">
            <Icons.Sparkles />
            <span className="text-xs font-bold uppercase tracking-widest">Global Travel Network</span>
          </div>
          <h1 className="text-5xl md:text-8xl font-serif font-bold text-slate-900 mb-8 tracking-tighter leading-[0.9]">
            Wander <br />
            <span className="bg-gradient-to-r from-orange-500 to-amber-600 bg-clip-text text-transparent italic">Limitless.</span>
          </h1>
        </div>
      </section>

      <SearchForm 
        onHotelSearch={handleHotelSearch} 
        onFlightSearch={handleFlightSearch} 
        onPackageSearch={handlePackageSearch}
        onAIFlightSearch={handleAIFlightSearch}
      />

      {/* Results Section */}
      <section id="search-results" className="max-w-7xl mx-auto px-4 py-24 min-h-[400px]">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-24 animate-in fade-in duration-500">
            <div className={`w-16 h-16 border-4 border-orange-500/20 border-t-orange-500 rounded-full animate-spin mb-6`}></div>
            <h3 className="text-2xl font-serif text-slate-800">
              {searchType === 'flights' ? 'AI Assistant is finding the best fares...' : 'Searching the globe...'}
            </h3>
            {searchType === 'flights' && <p className="text-slate-400 mt-2">Sorting options from lowest to highest price</p>}
          </div>
        )}

        {/* Hotel Results */}
        {!isSearching && hotels.length > 0 && (
          <div className="animate-in slide-in-from-bottom-8 duration-700">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-12 gap-4">
              <div>
                <h2 className="text-4xl font-serif font-bold text-slate-900">Hotel Inventory</h2>
                <p className="text-slate-500 mt-2">Live rates from OYO, TBO Holidays, and Luxury Partners</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <span className="bg-[#ee2a24] text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">OYO</span>
                <span className="bg-[#0056b3] text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">TBO Global</span>
                <span className="bg-slate-900 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">Premium</span>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {hotels.map(hotel => (
                <div key={hotel.id} className="bg-white rounded-3xl overflow-hidden shadow-sm hover:shadow-xl transition-all border border-slate-100 flex flex-col group">
                  <div className="aspect-video overflow-hidden relative">
                    <img src={hotel.imageUrl} alt={hotel.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                    <div className="absolute top-4 right-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg ${hotel.brand === 'Oyo' ? 'bg-[#ee2a24] text-white' : hotel.brand === 'TBO' ? 'bg-[#0056b3] text-white' : 'bg-white text-slate-900'}`}>
                        {hotel.brand}
                      </span>
                    </div>
                  </div>
                  <div className="p-6">
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="text-xl font-bold text-slate-900 line-clamp-1">{hotel.name}</h3>
                      <div className="text-orange-500 font-bold whitespace-nowrap">★ {hotel.rating}</div>
                    </div>
                    <p className="text-sm text-slate-500 mb-4 line-clamp-2">{hotel.description}</p>
                    <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-50">
                      <div>
                        <span className="text-2xl font-bold text-slate-900">₹{hotel.price.toLocaleString()}</span>
                        <span className="text-[10px] text-slate-400 uppercase font-bold ml-1">/night</span>
                      </div>
                      <button className={`px-6 py-2 rounded-xl text-xs font-bold transition-all active:scale-95 text-white ${hotel.brand === 'Oyo' ? 'bg-[#ee2a24]' : hotel.brand === 'TBO' ? 'bg-[#0056b3]' : 'bg-slate-900'}`}>
                        View Deal
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

