  const [searchType, setSearchType] = useState<'hotels' | 'flights' | 'packages'>('hotels');
  const [bookingSuccess, setBookingSuccess] = useState<{ id: string, amount: number, item: string } | null>(null);

  const handleLogin = (name: string, email: string) => {
    setUser({ name, email });
    setShowLogin(false);
  };

  const initiatePayment = (amount: number, itemName: string) => {
    if (!user) {
      setShowLogin(true);
      return;
    }

    const options = {
      key: "rzp_test_dummykey", // In production, this would be an environment variable
      amount: amount * 100, // Razorpay expects paise
      currency: "INR",
      name: "Vagabond AI",
      description: `Booking for ${itemName}`,
      image: "https://picsum.photos/200",
      handler: function (response: any) {
        setBookingSuccess({
          id: response.razorpay_payment_id,
          amount: amount,
          item: itemName
        });
      },
      prefill: {
        name: user.name,
        email: user.email,
        contact: "9999999999"
      },
      notes: {
        address: "Vagabond AI Headquarters, Bangalore"
      },
      theme: {
        color: "#f97316"
      }
    };

    const rzp = new (window as any).Razorpay(options);
    rzp.open();
  };

  const handleHotelClick = (hotel: Hotel) => {
    const query = encodeURIComponent(`${hotel.name} ${hotel.location}`);
    const url = `https://www.google.com/search?q=${query}`;
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  const handleHotelSearch = async (params: SearchParams) => {
    setSearchType('hotels');
    setIsSearching(true);
    setFlights([]);
    setPackages([]);
    setSearchResult(null);

    const [premiumResults, oyoResults, tboResults] = await Promise.all([
      searchPremiumHotels(params),
      searchOyoHotels(params),
      searchTboHotels(params)
    ]);

    const combined = [...premiumResults, ...oyoResults, ...tboResults].sort((a, b) => a.price - b.price);

    setHotels(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handleFlightSearch = async (params: FlightSearchParams) => {
    setSearchType('flights');
    setIsSearching(true);
    setHotels([]);
    setPackages([]);
    setSearchResult(null);
    const [indigoResults, airIndiaResults] = await Promise.all([
      searchIndigoFlights(params),
      searchAirIndiaFlights(params)
    ]);

    const combined = [...indigoResults, ...airIndiaResults].sort((a, b) => a.price - b.price);

    setFlights(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handleAIFlightSearch = async (query: string) => {
    setSearchType('flights');
    setIsSearching(true);
    setHotels([]);
    setPackages([]);
    setFlights([]);

    const parsedParams = await parseFlightQuery(query);

    const searchParams: FlightSearchParams = {
      location: parsedParams.location || 'Delhi',
      origin: parsedParams.origin || 'Mumbai',
      startDate: parsedParams.startDate || new Date().toISOString().split('T')[0],
      endDate: parsedParams.endDate || '',
      adults: parsedParams.adults || 1,
      children: parsedParams.children || 0,
      infants: parsedParams.infants || 0,
      childrenAges: [],
      tripType: parsedParams.tripType as any || 'one-way'
    };

    const [indigoResults, airIndiaResults] = await Promise.all([
      searchIndigoFlights(searchParams),
      searchAirIndiaFlights(searchParams)
    ]);

    const combined = [...indigoResults, ...airIndiaResults].sort((a, b) => a.price - b.price);

    setFlights(combined);
    setIsSearching(false);
    scrollToResults();
  };

  const handlePackageSearch = async (params: SearchParams) => {
    setSearchType('packages');
    setIsSearching(true);
    setHotels([]);
    setFlights([]);

    const [tboPackages, aiSuggestion] = await Promise.all([
      searchTboPackages(params),
      getTravelSuggestions(params)
    ]);

    setPackages(tboPackages);
    setSearchResult(aiSuggestion);
    setIsSearching(false);
    scrollToResults();
  };

  const scrollToResults = () => {
    setTimeout(() => {
      document.getElementById('search-results')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar user={user} onLoginClick={() => setShowLogin(true)} onLogout={() => setUser(null)} />

      {/* Hero */}
      <section className="relative pt-32 pb-20 md:pt-48 md:pb-32 overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-orange-50 to-transparent -z-10 blur-3xl opacity-50"></div>
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-white shadow-sm text-slate-600 mb-8 border border-slate-100">
            <Icons.Sparkles />
            <span className="text-xs font-bold uppercase tracking-widest">Global Travel Network</span>
          </div>
          <h1 className="text-5xl md:text-8xl font-serif font-bold text-slate-900 mb-8 tracking-tighter leading-[0.9]">
            Wander <br />
            <span className="bg-gradient-to-r from-orange-500 to-amber-600 bg-clip-text text-transparent italic">Limitless.</span>
          </h1>
        </div>
      </section>

      <SearchForm 
        onHotelSearch={handleHotelSearch} 
        onFlightSearch={handleFlightSearch} 
        onPackageSearch={handlePackageSearch}
        onAIFlightSearch={handleAIFlightSearch}
      />

      {/* Results Section */}
      <section id="search-results" className="max-w-7xl mx-auto px-4 py-24 min-h-[400px]">
        {isSearching && (
          <div className="flex flex-col items-center justify-center py-24 animate-in fade-in duration-500">
            <div className={`w-16 h-16 border-4 border-orange-500/20 border-t-orange-500 rounded-full animate-spin mb-6`}></div>
            <h3 className="text-2xl font-serif text-slate-800">
              {searchType === 'flights' ? 'AI Assistant is finding the best fares...' : 'Searching the globe...'}
            </h3>
            {searchType === 'flights' && <p className="text-slate-400 mt-2">Sorting options from lowest to highest price</p>}
          </div>
        )}

        {/* Hotel Results */}
        {!isSearching && hotels.length > 0 && (
          <div className="animate-in slide-in-from-bottom-8 duration-700">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-12 gap-4">
              <div>
                <h2 className="text-4xl font-serif font-bold text-slate-900">Hotel Inventory</h2>
                <p className="text-slate-500 mt-2">Live rates from OYO, TBO Holidays, and Luxury Partners</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <span className="bg-[#ee2a24] text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">OYO</span>
                <span className="bg-[#0056b3] text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">TBO Global</span>
                <span className="bg-slate-900 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold tracking-widest uppercase">Premium</span>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {hotels.map(hotel => (
                <div 
                  key={hotel.id} 
                  onClick={() => handleHotelClick(hotel)}
                  className="bg-white rounded-3xl overflow-hidden shadow-sm hover:shadow-xl transition-all border border-slate-100 flex flex-col group cursor-pointer hover:scale-[1.02] duration-300"
                >
                  <div className="aspect-video overflow-hidden relative">
                    <img src={hotel.imageUrl} alt={hotel.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                    <div className="absolute top-4 right-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg ${hotel.brand === 'Oyo' ? 'bg-[#ee2a24] text-white' : hotel.brand === 'TBO' ? 'bg-[#0056b3] text-white' : 'bg-white text-slate-900'}`}>
                        {hotel.brand}
                      </span>
                    </div>
                  </div>
                  <div className="p-6">
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="text-xl font-bold text-slate-900 line-clamp-1">{hotel.name}</h3>
                      <div className="text-orange-500 font-bold whitespace-nowrap">★ {hotel.rating}</div>
                    </div>
                    <p className="text-sm text-slate-500 mb-4 line-clamp-2">{hotel.description}</p>
                    <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-50">
                      <div>
                        <span className="text-2xl font-bold text-slate-900">₹{hotel.price.toLocaleString()}</span>
                        <span className="text-[10px] text-slate-400 uppercase font-bold ml-1">/night</span>
                      </div>
                      <div className="flex space-x-2">
                         <button 
                          onClick={(e) => { e.stopPropagation(); handleHotelClick(hotel); }}
                          className={`px-4 py-2 rounded-xl text-[10px] font-bold transition-all border border-slate-200 text-slate-600 hover:bg-slate-50`}
                        >
                          Details
                        </button>
                        <button 
                          onClick={(e) => { e.stopPropagation(); initiatePayment(hotel.price, hotel.name); }}
                          className={`px-4 py-2 rounded-xl text-[10px] font-bold transition-all active:scale-95 text-white ${hotel.brand === 'Oyo' ? 'bg-[#ee2a24]' : hotel.brand === 'TBO' ? 'bg-[#0056b3]' : 'bg-slate-900'}`}
                        >
                          Book
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Package Results */}
        {!isSearching && packages.length > 0 && (
          <div className="animate-in slide-in-from-bottom-8 duration-700 mb-16">
            <h2 className="text-4xl font-serif font-bold text-slate-900 mb-8">TBO Holiday Packages</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-12">
              {packages.map(pkg => (
                <div key={pkg.id} className="bg-white rounded-[2.5rem] overflow-hidden border border-slate-100 shadow-sm hover:shadow-2xl transition-all group">
                  <div className="h-64 relative overflow-hidden">
                    <img src={pkg.imageUrl} alt={pkg.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                    <div className="absolute bottom-6 left-6 text-white">
                      <p className="text-[10px] font-bold uppercase tracking-widest text-orange-400 mb-1">{pkg.duration}</p>
                      <h3 className="text-xl font-bold">{pkg.title}</h3>
                    </div>
                  </div>
                  <div className="p-8">
                    <div className="flex items-center space-x-2 mb-6">
                       {pkg.inclusions.slice(0, 3).map((inc, i) => (
                         <span key={i} className="text-[9px] font-bold uppercase tracking-widest bg-slate-50 text-slate-400 px-2 py-1 rounded-md">{inc}</span>
                       ))}
                    </div>
                    <div className="flex items-center justify-between">
                       <div>
                         <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Total Package Value</p>
                         <div className="text-2xl font-bold text-slate-900">₹{pkg.price.toLocaleString()}</div>
                       </div>
                       <button 
                        onClick={() => initiatePayment(pkg.price, pkg.title)}
                        className="bg-[#0056b3] text-white px-6 py-3 rounded-2xl text-xs font-bold shadow-lg shadow-blue-100 active:scale-95 transition-all"
                       >
                         Reserve
                       </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {searchResult && (
              <div className="bg-gradient-to-br from-slate-900 to-slate-800 rounded-[3rem] p-8 md:p-16 text-white shadow-2xl relative overflow-hidden">
                 <div className="relative z-10 grid md:grid-cols-2 gap-16 items-center">
                    <div>
                      <h2 className="text-4xl md:text-5xl font-serif font-bold mb-8 leading-tight">AI Concierge: <br/>The {searchResult.title}</h2>
                      <p className="text-slate-300 text-lg mb-8">{searchResult.vibe}</p>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-8 border border-white/10">
                      <h3 className="text-2xl font-serif font-bold mb-6">Local Highlights</h3>
                      <ul className="space-y-4">
                        {searchResult.highlights.map((h, i) => (
                          <li key={i} className="flex items-center space-x-4"><div className="h-2 w-2 rounded-full bg-orange-500"></div><span className="text-slate-100">{h}</span></li>
                        ))}
                      </ul>
                    </div>
                 </div>
              </div>
            )}
          </div>
        )}

        {/* Flight Results */}
        {!isSearching && flights.length > 0 && (
          <div className="animate-in slide-in-from-bottom-8 duration-700">
            <div className="flex justify-between items-end mb-12">
              <div>
                <h2 className="text-4xl font-serif font-bold text-slate-900">Flight Connections</h2>
                <p className="text-slate-500 mt-2">Showing cheapest flights first</p>
              </div>
              <div className="flex space-x-2">
                 <div className="flex items-center space-x-1 px-3 py-1 bg-green-50 text-green-700 rounded-full text-[10px] font-bold uppercase">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span>Lowest Fares Guaranteed</span>
                 </div>
              </div>
            </div>
            <div className="space-y-4">
              {flights.map(flight => (
                <div key={flight.id} className="bg-white rounded-3xl p-6 md:p-10 border border-slate-100 shadow-sm hover:shadow-xl transition-all flex flex-col md:flex-row items-center gap-8 group">
                  <div className="flex flex-col items-center justify-center space-y-2 min-w-[120px]">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${flight.airline === 'Indigo' ? 'bg-slate-50 text-[#00316e]' : 'bg-red-50 text-red-600'}`}>
                      <Icons.Plane />
                    </div>
                    <span className="font-bold text-slate-800">{flight.flightNumber}</span>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">{flight.airline}</span>
                  </div>
                  <div className="flex-1 grid grid-cols-3 items-center text-center">
                    <div>
                      <div className="text-2xl font-bold text-slate-900">{flight.departureTime}</div>
                      <div className="text-xs font-bold text-slate-400 uppercase">{flight.origin}</div>
                    </div>
                    <div className="relative px-8">
                       <div className="h-px bg-slate-200 w-full relative">
                         <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white px-2 text-[10px] font-bold text-slate-400">
                           {flight.duration}
                         </div>
                       </div>
                       <p className="text-[10px] mt-2 text-slate-400 font-bold uppercase">{flight.stops === 0 ? 'Non-stop' : `${flight.stops} Stop`}</p>
                    </div>
                    <div>
                      <div className="text-2xl font-bold text-slate-900">{flight.arrivalTime}</div>
                      <div className="text-xs font-bold text-slate-400 uppercase">{flight.destination}</div>
                    </div>
                  </div>
                  <div className="flex flex-col items-end">
                    <span className="text-[10px] font-bold uppercase text-orange-500 mb-1">{flight.tier}</span>
                    <div className="text-3xl font-bold text-slate-900">₹{flight.price.toLocaleString()}</div>
                    <button 
                      onClick={() => initiatePayment(flight.price, `Flight ${flight.flightNumber}`)}
                      className="mt-2 bg-slate-900 text-white px-8 py-3 rounded-2xl text-sm font-bold shadow-lg shadow-slate-200 active:scale-95 transition-all"
                    >
                      Book Ticket
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </section>

      {/* Featured Destinations */}
      <section className="max-w-7xl mx-auto px-4 pb-24">
        <h2 className="text-4xl font-serif font-bold text-slate-900 mb-12">Handpicked Destinations</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {FEATURED_DESTINATIONS.map(d => <DestinationCard key={d.id} destination={d} />)}
        </div>
      </section>

      {/* Success Modal */}
      {bookingSuccess && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setBookingSuccess(null)}></div>
          <div className="relative bg-white rounded-[3rem] p-12 max-w-lg w-full text-center shadow-2xl animate-in zoom-in duration-300">
             <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-8 animate-checkmark">
                <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" /></svg>
             </div>
             <h2 className="text-4xl font-serif font-bold text-slate-900 mb-4">Booking Confirmed!</h2>
             <p className="text-slate-500 mb-8">Your trip to {bookingSuccess.item} is all set. We've sent the details to your email.</p>
             <div className="bg-slate-50 rounded-3xl p-6 mb-8 text-left space-y-2">
                <div className="flex justify-between text-xs font-bold uppercase tracking-widest text-slate-400">
                  <span>Payment ID</span>
                  <span className="text-slate-900">{bookingSuccess.id.slice(-8).toUpperCase()}</span>
                </div>
                <div className="flex justify-between text-xs font-bold uppercase tracking-widest text-slate-400">
                  <span>Amount Paid</span>
                  <span className="text-slate-900">₹{bookingSuccess.amount.toLocaleString()}</span>
                </div>
             </div>
             <button 
              onClick={() => setBookingSuccess(null)}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold shadow-xl shadow-slate-200 active:scale-95 transition-all"
             >
               Go to My Trips
             </button>
          </div>
        </div>
      )}

      {showLogin && <LoginModal onClose={() => setShowLogin(false)} onLogin={handleLogin} />}
    </div>
  );
};

export default App;
